namespace BgControls.Windows.Input.Touch;/// <summary>/// 滑动手势识别器的工厂类，用于创建滑动识别实例并定义相关手势转换./// </summary>public class SwipeGestureRecognizerFactory : IGestureRecognizerFactory{    /// <summary>    /// Initializes a new instance of the <see cref="SwipeGestureRecognizerFactory"/> class.    /// </summary>    public SwipeGestureRecognizerFactory()    {    }    /// <summary>    /// Gets 滑动手势识别器的优先级.    /// </summary>    public int Priority => TouchManager.SwipePriority;    /// <summary>    /// 为指定的 UI 元素创建滑动手势识别器实例.    /// </summary>    /// <param name="element">关联的 UI 元素.</param>    /// <returns>滑动手势识别器实例.</returns>    public GestureRecognizerBase CreateGestureRecognizer(UIElement element)    {        // 验证传入的元素参数是否为空.        ArgumentNullException.ThrowIfNull(element, nameof(element));        return new SwipeGestureRecognizer(element);    }    /// <summary>    /// 注册手势状态机中的滑动手势转换规则.    /// </summary>    public void RegisterGestureTransitions()    {        // 注册滑动（Swipe）手势允许转换为捏合（Pinch）手势的规则.        GestureManager.RegisterGestureTransitions(TouchManager.SwipeGestureName, new HashSet<string>        {            TouchManager.PinchGestureName,        });    }}